    {
      "title": "German Family Panel (pairfam)",
      "host": "GESIS",
      "topicsMatched": [
        "Reproductive health",
        "Family life and marriage"
      ],
      "description": "Longitudinal panel study on partnerships, fertility intentions and outcomes, parenting, and family dynamics in Germany."
    },
    {
      "title": "ALLBUS (German General Social Survey)",
      "host": "GESIS",
      "topicsMatched": [
        "Family life and marriage",
        "Specific diseases, disorders and medical conditions"
      ],
      "description": "Repeated cross-sectional survey of the German population covering social attitudes and behaviors; includes modules on family and marriage as well as health-related topics."
    },
    {
      "title": "Eurobarometer – Public Health and HIV/AIDS modules (GESIS Eurobarometer Archive)",
      "host": "GESIS",
      "topicsMatched": [
        "Reproductive health",
        "Specific diseases, disorders and medical conditions"
      ],
      "description": "Special Eurobarometer surveys on public health topics such as HIV/AIDS, vaccination, cancer, tobacco and alcohol, archived by GESIS as part of the Eurobarometer series."
    },
    {
      "title": "Population Policy Acceptance Survey (PPAS)",
      "host": "GESIS",
      "topicsMatched": [
        "Reproductive health",
        "Family life and marriage"
      ],
      "description": "Survey on fertility, family planning, and attitudes toward population and family policies in Europe, including German data archived by GESIS."
    },
    {
      "title": "DJI Family Survey (German Youth Institute)",
      "host": "GESIS",
      "topicsMatched": [
        "Family life and marriage"
      ],
      "description": "Survey series on family life, partnership, marriage, parenting, and work–family balance in Germany archived at GESIS."
    },
    {
      "title": "ISSP – Family and Changing Gender Roles",
      "host": "GESIS",
      "topicsMatched": [
        "Family life and marriage"
      ],
      "description": "International Social Survey Programme module focusing on family roles, marriage, gender roles, and related attitudes; German data are archived by GESIS."
    },
    {
      "title": "ISSP – Health and Health Care",
      "host": "GESIS",
      "topicsMatched": [
        "Specific diseases, disorders and medical conditions"
      ],
      "description": "International Social Survey Programme module on health status, health care utilization, and attitudes toward health services; German data are archived by GESIS."
    },
    {
      "title": "European Values Study (EVS) – Germany",
      "host": "GESIS",
      "topicsMatched": [
        "Family life and marriage"
      ],
      "description": "Cross-national survey of values including family, marriage, and related social norms; German waves are archived by GESIS."
    }
  ]
}
